import scipy
import numpy as np

import math

def cholesky_decomposition(matrix: list[list[float]]) -> list[list[float]]:
    n = len(matrix)
    L = [[0.0] * n for _ in range(n)]

    for i in range(n):
        for j in range(i + 1):
            s = sum(L[i][k] * L[j][k] for k in range(j))
            if i == j:
                L[i][j] = math.sqrt(matrix[i][i] - s)
            else:
                L[i][j] = (matrix[i][j] - s) / L[j][j]
    return L
